/*!
FullCalendar v6.1.8
*/
class FullCalendar{static Calendar=e=>new t(e)};class t{constructor(e){this.el=e.el,this.options=e,this.events=e.events||[]}render(){this.el.innerHTML=this.build()}build(){let e="<div class='fc'>";return e+=this.buildHeader(),e+=this.buildGrid(),e+="</div>",e}buildHeader(){return`
<div class="fc-toolbar">
  <div class="fc-toolbar-title">Calendrier</div>
</div>`}buildGrid(){let e="<div class='fc-daygrid'>";for(let t=1;t<=30;t++)e+=`
  <div class="fc-daygrid-day">
    <div class="fc-daygrid-day-number">${t}</div>
  </div>`;return e+="</div>",e}}
window.FullCalendar=FullCalendar;
